<div class="srv-docs-three-cols" style="grid-template-columns: repeat(auto-fit, minmax(320px, 1fr)); margin-bottom: 30px;">
    <!-- Proprietorship Documents -->
    <div class="srv-docs-col">
        <h3>
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path><polyline points="14 2 14 8 20 8"></polyline><line x1="16" y1="13" x2="8" y2="13"></line><line x1="16" y1="17" x2="8" y2="17"></line><polyline points="10 9 9 9 8 9"></polyline></svg>
            For Proprietorship (Single Owner)
        </h3>
        <div class="srv-docs-num-list">
            <div class="srv-docs-num-item"><div class="srv-docs-number">1</div><div class="srv-docs-text">PAN Card</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">2</div><div class="srv-docs-text">Aadhaar Card</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">3</div><div class="srv-docs-text">GST Registration Certificate <span>(If Available)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">4</div><div class="srv-docs-text">MSME / Udyam Registration <span>(If Available)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">5</div><div class="srv-docs-text">Firm Registration Certificate <span>(If Available)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">6</div><div class="srv-docs-text">Shops & Establishments Registration <span>(If Available)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">7</div><div class="srv-docs-text">Business Address Proof</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">8</div><div class="srv-docs-text">House Tax Receipt</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">9</div><div class="srv-docs-text">Current Electricity Bill</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">10</div><div class="srv-docs-text">Rental Agreement <span>(If Premises is Rented)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">11</div><div class="srv-docs-text">Lease Agreement <span>(If Premises is on Lease)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">12</div><div class="srv-docs-text">Cancelled Cheque / Bank Passbook</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">13</div><div class="srv-docs-text">Mobile Number</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">14</div><div class="srv-docs-text">Email ID</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">15</div><div class="srv-docs-text">Digital Signature Certificate (DSC) <span>(If Available)</span></div></div>
        </div>
    </div>
    
    <!-- Partnership Firm / Company / LLP Documents -->
    <div class="srv-docs-col">
        <h3>
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path><polyline points="14 2 14 8 20 8"></polyline><line x1="16" y1="13" x2="8" y2="13"></line><line x1="16" y1="17" x2="8" y2="17"></line><polyline points="10 9 9 9 8 9"></polyline></svg>
            For Partnership Firm / Company / LLP
        </h3>
        <div class="srv-docs-num-list">
            <div class="srv-docs-num-item"><div class="srv-docs-number">1</div><div class="srv-docs-text">Firm PAN Card</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">2</div><div class="srv-docs-text">Partnership Deed / Certificate of Incorporation</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">3</div><div class="srv-docs-text">Firm Registration Certificate</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">4</div><div class="srv-docs-text">GST Registration Certificate</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">5</div><div class="srv-docs-text">Aadhaar & PAN of Authorized Signatory AND Partners <span>(Along with contact numbers and email IDs)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">6</div><div class="srv-docs-text">Business Address Proof</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">7</div><div class="srv-docs-text">House Tax Receipt</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">8</div><div class="srv-docs-text">Current Electricity Bill</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">9</div><div class="srv-docs-text">Rental Agreement <span>(If Premises is Rented)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">10</div><div class="srv-docs-text">Lease Agreement <span>(If Premises is on Lease)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">11</div><div class="srv-docs-text">Cancelled Cheque / Bank Passbook</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">12</div><div class="srv-docs-text">Mobile Number</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">13</div><div class="srv-docs-text">Email ID</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">14</div><div class="srv-docs-text">Digital Signature Certificate (DSC) <span>(If Available)</span></div></div>
        </div>
    </div>
</div>
